export const CSSColorMode: {
    HEX: "hex";
    HEXA: "hexa";
    RGB_CSS: "rgb-css";
    RGBA_CSS: "rgba-css";
    HSL_CSS: "hsl-css";
    HSLA_CSS: "hsla-css";
};

export type CSSColorMode = Enumify<typeof CSSColorMode>;

export const ObjectColorMode: {
    RGB: "rgb";
    RGBA: "rgba";
    HSL: "hsl";
    HSLA: "hsla";
    HSV: "hsv";
    HSVA: "hsva";
};

export type ObjectColorMode = Enumify<typeof ObjectColorMode>;

export type Format = "auto" | SupportedMode;

export type Enumify<T> = T[keyof T];

export type SupportedMode = CSSColorMode | ObjectColorMode;